parameters.jsCode:
// Emit one item per active product for PM self-assessment
const dateKey = new Date().toISOString().split('T')[0];
const weekNum = Math.ceil((new Date().getTime() - new Date(new Date().getFullYear(), 0, 1).getTime()) / (7 * 24 * 60 * 60 * 1000));

const products = [
  {
    id: 'EOS',
    name: 'EstateOS',
    workingDir: '{{DEFAULT_WORKING_DIR}}',
    domain: 'estate planning & probate'
  },
  {
    id: 'CER',
    name: 'OrchestraCode',
    workingDir: '{{DEFAULT_WORKING_DIR}}',
    domain: 'supply chain compliance & certification'
  },
  {
    id: 'WMS',
    name: 'WarrantyManagement',
    workingDir: '{{DEFAULT_WORKING_DIR}}',
    domain: 'warranty claims & RMA'
  }
];

return products.map(p => ({
  json: {
    ...p,
    dateKey,
    weekNum,
    idempotencyKey: `pm-self-assess:${p.id}:${dateKey}`
  }
}));

